// Extract answer key and student answer
const item = $input.first().json;

// Parse JSON nếu là string
const parseJson = (data) => {
  if (typeof data === 'string') {
    try {
      return JSON.parse(data);
    } catch (e) {
      return null;
    }
  }
  return data;
};

const answerKey = parseJson(item.answer_extract) || {};
const studentAnswer = parseJson(item.submission_extract) || {};

if (!answerKey.questions || !Array.isArray(answerKey.questions)) {
  throw new Error(`Exam ${item.exam_code} khong co answer key hop le`);
}
if (!studentAnswer || !Array.isArray(studentAnswer)) {
  throw new Error(`Submission ${item.submission_id} khong co student answer hop le`);
}

return [{
  json: {
    submission_id: item.submission_id,
    exam_id: item.exam_id,
    student_code: item.student_code,
    student_name: item.student_name,
    exam_code: item.exam_code,
    exam_title: item.exam_title,
    class_code: item.class_code || item.exam_class_code || null,
    subject_code: item.subject_code || item.exam_subject_code || null,
    answer_key: answerKey,
    student_answer: studentAnswer
  }
}];

const meta = $('Extract Answer Key & Student Answer').first().json;
const gradingText = String($input.first().json.grading_text || '').trim();

if (!gradingText) {
  throw new Error('GPT khong tra ve ket qua cham diem');
}

let gradingResult;
try {
  gradingResult = JSON.parse(gradingText);
} catch (error) {
  throw new Error(`Khong parse duoc JSON grading result: ${error.message}`);
}

if (!gradingResult || typeof gradingResult !== 'object') {
  throw new Error('Grading result khong dung dinh dang object');
}

const gradedQuestions = Array.isArray(gradingResult.graded_questions) ? gradingResult.graded_questions : [];

const totalScore = gradedQuestions.reduce((sum, q) => {
  const earned = Number(q.earned_score || 0);
  return sum + (Number.isFinite(earned) ? earned : 0);
}, 0);

const totalMaxScore = gradedQuestions.reduce((sum, q) => {
  const max = Number(q.max_score || 0);
  return sum + (Number.isFinite(max) ? max : 0);
}, 0);

const normalizedGradingResult = {
  graded_questions: gradedQuestions.map(q => ({
    question_no: String(q.question_no || ''),
    max_score: Number(q.max_score || 0),
    earned_score: Number(q.earned_score || 0),
    feedback: String(q.feedback || ''),
    rubric_scores: Array.isArray(q.rubric_scores) ? q.rubric_scores.map(r => ({
      key: String(r.key || ''),
      score: Number(r.score || 0),
      earned: Number(r.earned || 0),
      comment: String(r.comment || '')
    })) : []
  })),
  total_score: Number(totalScore.toFixed(2)),
  total_max_score: Number(totalMaxScore.toFixed(2)),
  graded_at: new Date().toISOString()
};

return [{
  json: {
    submission_id: meta.submission_id,
    exam_id: meta.exam_id,
    student_code: meta.student_code,
    student_name: meta.student_name,
    exam_code: meta.exam_code,
    exam_title: meta.exam_title,
    class_code: meta.class_code,
    subject_code: meta.subject_code,
    total_score: normalizedGradingResult.total_score,
    grading_result: normalizedGradingResult
  }
}];

const data = $input.first().json;

function escapeLiteral(value) {
  return String(value ?? '').replace(/'/g, "''");
}

function sqlString(value) {
  if (!value) return 'NULL';
  return `'${escapeLiteral(value)}'`;
}

function sqlNumber(value) {
  const number = Number(value);
  return Number.isFinite(number) ? String(number) : 'NULL';
}

function sqlJson(value) {
  if (value === undefined || value === null) {
    return 'NULL';
  }
  return `'${escapeLiteral(JSON.stringify(value))}'::jsonb`;
}

const maxScore = data.grading_result?.total_max_score || null;

const sql = `
INSERT INTO grading_results (
  submission_id,
  exam_id,
  exam_code,
  exam_title,
  class_code,
  subject_code,
  student_code,
  student_name,
  grading_type,
  total_score,
  max_score,
  grading_detail,
  graded_by,
  graded_by_name,
  status
) VALUES (
  ${sqlNumber(data.submission_id)},
  ${sqlNumber(data.exam_id)},
  ${sqlString(data.exam_code)},
  ${sqlString(data.exam_title)},
  ${sqlString(data.class_code)},
  ${sqlString(data.subject_code)},
  ${sqlString(data.student_code)},
  ${sqlString(data.student_name)},
  'auto',
  ${sqlNumber(data.total_score)},
  ${sqlNumber(maxScore)},
  ${sqlJson(data.grading_result)},
  0,
  'System (AI)',
  'completed'
) RETURNING id, submission_id, exam_id, student_code, total_score, grading_attempt, graded_at;`;

return [{
  json: {
    submission_id: data.submission_id,
    exam_id: data.exam_id,
    student_code: data.student_code,
    student_name: data.student_name,
    exam_code: data.exam_code,
    exam_title: data.exam_title,
    class_code: data.class_code,
    subject_code: data.subject_code,
    total_score: data.total_score,
    grading_result: data.grading_result,
    sql
  }
}];

const result = $('Build Insert SQL').first().json;

return [{
  json: {
    ok: true,
    message: `Successfully graded submission ${result.submission_id}`,
    submission_id: result.submission_id,
    score: result.score
  }
}];
